namespace QAHub.Api.Domain.Integrations;
public sealed class AutomationRun
{
 private AutomationRun(){}
 public AutomationRun(Guid productId,string provider,string externalRunId,string branch,string commitSha,string status,int total,int passed,int failed,int skipped,string owner,string fingerprint){if(productId==Guid.Empty)throw new ArgumentException("Product is required.");ArgumentException.ThrowIfNullOrWhiteSpace(provider);ArgumentException.ThrowIfNullOrWhiteSpace(externalRunId);ArgumentException.ThrowIfNullOrWhiteSpace(owner);if(total<0||passed<0||failed<0||skipped<0||passed+failed+skipped>total)throw new ArgumentOutOfRangeException(nameof(total),"Result counts are inconsistent.");Id=Guid.NewGuid();ProductId=productId;Provider=provider.Trim();ExternalRunId=externalRunId.Trim();Branch=branch.Trim();CommitSha=commitSha.Trim();Status=status.Trim();Total=total;Passed=passed;Failed=failed;Skipped=skipped;Owner=owner.Trim();Fingerprint=fingerprint;ReceivedAtUtc=DateTimeOffset.UtcNow;}
 public Guid Id{get;private set;}public Guid ProductId{get;private set;}public string Provider{get;private set;}=string.Empty;public string ExternalRunId{get;private set;}=string.Empty;public string Branch{get;private set;}=string.Empty;public string CommitSha{get;private set;}=string.Empty;public string Status{get;private set;}=string.Empty;public int Total{get;private set;}public int Passed{get;private set;}public int Failed{get;private set;}public int Skipped{get;private set;}public string Owner{get;private set;}=string.Empty;public string Fingerprint{get;private set;}=string.Empty;public DateTimeOffset ReceivedAtUtc{get;private set;}
}
